  ('elementary-10ced7e2-moex-00011', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-114-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '依公務人員任用法規定，下列關於現職公務人員之調任之敘述，何者錯誤？', '["除簡任第12職等以上人員外，其餘各職等人員，得在各職系之職務間予以調任", "經依法任用人員，除自願者外，不得調任低一官等之職務", "在同官等內而自願調任低職等職務者，以調任低一職等之職務為限，仍以原職等任用", "副主管人員不得調任本單位之非主管"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:43+00:00", "source_pdf_sha1": "1c4136f91ea6", "answer_pdf_sha1": "852b4a0e93ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "509", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 11, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
