  ('elementary-10ced7e2-moex-00013', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-114-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '下列有關公務人員考試法之規定，何者錯誤？', '["公務人員考試得採心理測驗方式行之", "筆試應一律使用本國文字作答", "公務人員考試除單採筆試者外，其他應併採二種以上方式", "因懷孕或生產前後無法參加體能測驗者，得保留筆試成績"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:43+00:00", "source_pdf_sha1": "1c4136f91ea6", "answer_pdf_sha1": "852b4a0e93ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "509", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00014', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-114-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '公務人員考試錄取者，不論是正額與增額，在下列那一條件下皆可保留資格，不用馬上接受分配訓練？', '["正在修讀學士學位", "正在修讀碩士學位", "養育3足歲以下子女", "父母病危"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:43+00:00", "source_pdf_sha1": "1c4136f91ea6", "answer_pdf_sha1": "852b4a0e93ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "509", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00015', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-114-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '關於公務人員任用法所規範之任用親屬限制，下列敘述何者錯誤？', '["各機關長官對於配偶，不得在本機關任用", "各機關長官對於三親等以內血親、姻親，不得任用為直接隸屬機關之長官", "各機關長官之配偶，係在各該長官接任以前任用者，於長官接任後3個月內應辭職或調任其他機關", "對於本機關各級主管長官之配偶及三親等以內血親、姻親，在其主管單位中應迴避任用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:43+00:00", "source_pdf_sha1": "1c4136f91ea6", "answer_pdf_sha1": "852b4a0e93ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "509", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00016', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-114-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '各機關對職務列等及職務相當之所屬人員，應配合職務性質及業務需要實施各種遷調，下列敘述何者錯誤？', '["本機關內部單位主管間或副主管間之遷調", "本機關非主管人員間之遷調", "本機關與所屬機關間或所屬機關間非主管人員之遷調", "本機關與他機關首長、副首長間之遷調"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:43+00:00", "source_pdf_sha1": "1c4136f91ea6", "answer_pdf_sha1": "852b4a0e93ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "509", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00017', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-114-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '公務人員任用法中有關試用人員之規定，下列何者錯誤？', '["試用人員試用期滿成績及格，予以實授", "曠職繼續達2日或累積達3日，應為試用成績不及格", "平時考核獎懲互相抵銷後，累積達一大過以上，應為試用成績不及格", "試用成績不及格人員，自機關首長核定之日起予以停職"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:43+00:00", "source_pdf_sha1": "1c4136f91ea6", "answer_pdf_sha1": "852b4a0e93ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "509", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00018', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-114-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '各機關辦理機要職務人員（下稱機要人員）之規定，依公務人員任用法及其施行細則，下列敘述何者正確？', '["擔任經銓敘部同意列為機要職務，得不受法定任用資格限制", "各機關任用之機要人員得不具法定任用資格，但仍須先經銓敘審定", "機關長官停職或休職時，機要人員應同時離職", "機要人員如改任其他須具法定任用資格之職務，得不受重新銓敘審定其任用資格之限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:43+00:00", "source_pdf_sha1": "1c4136f91ea6", "answer_pdf_sha1": "852b4a0e93ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "509", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
